Here's a modern MSTest 3.x test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange
        var handler = new DelayedHttpHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CooperativeTimeout_RespectsCancellation()
    {
        // Arrange — uses TestContext.CancellationToken which fires when [Timeout] expires
        var handler = new DelayedHttpHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — test passes because [Timeout] triggers cancellation
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }
}
```

And the test helpers:

```csharp
// Returns a canned response immediately
internal sealed class FakeHttpHandler(string content, HttpStatusCode statusCode)
    : HttpMessageHandler
{
    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();
        var response = new HttpResponseMessage(statusCode)
        {
            Content = new StringContent(content)
        };
        return Task.FromResult(response);
    }
}

// Simulates a slow server to test cancellation/timeout
internal sealed class DelayedHttpHandler(TimeSpan delay) : HttpMessageHandler
{
    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        await Task.Delay(delay, cancellationToken); // throws when cancelled
        return new HttpResponseMessage(HttpStatusCode.OK);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---------|-----|
| `TestContext` via constructor | Enables `readonly`, avoids nullability warnings |
| `[Timeout(N)]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest fires the token when time expires |
| Separate `CancellationTokenSource` | Tests caller-initiated cancellation independently |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not subclasses) |
| Custom `HttpMessageHandler` | Avoids real network calls; controls timing |

The critical insight: `[Timeout]` alone just fails the test after the deadline. To actually *stop* the async work, you must pass `TestContext.CancellationToken` into your async calls — that's cooperative cancellation.
